from __future__ import annotations

import heapq
from dataclasses import dataclass, field, replace
from datetime import datetime, timezone
from enum import Enum
from itertools import count
from types import TracebackType
from typing import Callable, Generic, Iterable, Iterator, TypeAlias, TypeVar
from uuid import UUID, uuid4

T = TypeVar("T")

TaskId: TypeAlias = UUID
TaskIdLike: TypeAlias = UUID | str
HeapEntry: TypeAlias = tuple[int, int, UUID]


__all__ = [
    "EmptyQueueError",
    "PriorityTaskQueue",
    "PriorityTaskQueueError",
    "Task",
    "TaskId",
    "TaskNotFoundError",
    "TaskStatus",
]


def _utc_now() -> datetime:
    """Return the current timezone-aware UTC datetime."""
    return datetime.now(timezone.utc)


def _validate_priority_value(priority: int) -> None:
    """Validate that a priority value is an integer."""
    if not isinstance(priority, int) or isinstance(priority, bool):
        raise TypeError("priority must be an int")


class TaskStatus(str, Enum):
    """Lifecycle states for tasks managed by PriorityTaskQueue."""

    PENDING = "pending"
    DEQUEUED = "dequeued"
    CANCELED = "canceled"


@dataclass(frozen=True, slots=True, kw_only=True)
class Task(Generic[T]):
    """Immutable task record stored by PriorityTaskQueue."""

    id: UUID = field(default_factory=uuid4)
    payload: T
    priority: int
    created_at: datetime = field(default_factory=_utc_now)
    status: TaskStatus = TaskStatus.PENDING

    def __post_init__(self) -> None:
        """Validate directly constructed Task instances."""
        if not isinstance(self.id, UUID):
            raise TypeError("id must be a UUID")

        _validate_priority_value(self.priority)

        if not isinstance(self.created_at, datetime):
            raise TypeError("created_at must be a datetime")

        if self.created_at.tzinfo is None or self.created_at.utcoffset() is None:
            raise ValueError("created_at must be timezone-aware")

        if not isinstance(self.status, TaskStatus):
            object.__setattr__(self, "status", TaskStatus(self.status))


class PriorityTaskQueueError(Exception):
    """Base exception for PriorityTaskQueue errors."""


class EmptyQueueError(PriorityTaskQueueError):
    """Raised when reading from an empty queue."""


class TaskNotFoundError(PriorityTaskQueueError):
    """Raised when a task ID does not identify a pending task."""


class PriorityTaskQueue(Generic[T]):
    """A stable priority queue for tasks.

    Higher integer priority values are returned first. Tasks with equal priority
    are returned FIFO. Updating a task to a different priority places it at the
    back of the FIFO group for the new priority.
    """

    def __init__(self, tasks: Iterable[tuple[T, int]] | None = None) -> None:
        """Create a queue, optionally seeded with `(payload, priority)` pairs."""
        self._tasks: dict[UUID, Task[T]] = {}
        self._heap: list[HeapEntry] = []
        self._queue_order: dict[UUID, int] = {}
        self._sequence: Iterator[int] = count()

        if tasks is not None:
            for payload, priority in tasks:
                self.add_task(payload, priority)

    @property
    def size(self) -> int:
        """Return the number of pending tasks."""
        return len(self._tasks)

    def add_task(self, payload: T, priority: int) -> Task[T]:
        """Add a task and return its generated Task record."""
        _validate_priority_value(priority)
        task = Task(payload=payload, priority=priority)
        self._push_pending_task(task)
        return task

    def get_next_task(self) -> Task[T]:
        """Remove and return the next highest-priority task.

        Raises:
            EmptyQueueError: If the queue has no pending tasks.
        """
        self._discard_stale_heap_entries()

        if not self._heap:
            raise EmptyQueueError("Cannot get a task from an empty queue.")

        _, _, task_id = heapq.heappop(self._heap)
        task = self._tasks.pop(task_id)
        self._queue_order.pop(task_id, None)

        return replace(task, status=TaskStatus.DEQUEUED)

    def peek_next_task(self) -> Task[T]:
        """Return the next highest-priority task without removing it.

        Raises:
            EmptyQueueError: If the queue has no pending tasks.
        """
        self._discard_stale_heap_entries()

        if not self._heap:
            raise EmptyQueueError("Cannot peek at an empty queue.")

        _, _, task_id = self._heap[0]
        return self._tasks[task_id]

    def get_task(self, task_id: TaskIdLike) -> Task[T]:
        """Return a pending task by ID without removing it."""
        _, task = self._require_task(task_id)
        return task

    def cancel_task(self, task_id: TaskIdLike) -> Task[T]:
        """Cancel and remove a pending task by ID.

        Returns the removed task with status TaskStatus.CANCELED.

        Raises:
            TaskNotFoundError: If no pending task has the given ID.
        """
        task_uuid, task = self._require_task(task_id)
        self._tasks.pop(task_uuid)
        self._queue_order.pop(task_uuid, None)
        self._compact_heap_if_needed()

        return replace(task, status=TaskStatus.CANCELED)

    def remove_task(self, task_id: TaskIdLike) -> Task[T]:
        """Remove a pending task by ID.

        This is an alias for cancel_task.
        """
        return self.cancel_task(task_id)

    def update_task_priority(self, task_id: TaskIdLike, priority: int) -> Task[T]:
        """Update a pending task's priority and return the updated Task.

        Raises:
            TaskNotFoundError: If no pending task has the given ID.
        """
        _validate_priority_value(priority)
        task_uuid, task = self._require_task(task_id)

        if task.priority == priority:
            return task

        updated = replace(task, priority=priority)
        self._tasks[task_uuid] = updated
        self._push_pending_task(updated)

        return updated

    def list_tasks(self, *, priority: int | None = None) -> list[Task[T]]:
        """Return pending tasks in dequeue order, optionally filtered by priority."""
        if priority is not None:
            _validate_priority_value(priority)

        tasks = self._ordered_tasks()

        if priority is None:
            return tasks

        return [task for task in tasks if task.priority == priority]

    def tasks_with_priority(self, priority: int) -> list[Task[T]]:
        """Return pending tasks with the given priority in dequeue order."""
        return self.list_tasks(priority=priority)

    def filter_tasks(self, predicate: Callable[[Task[T]], bool]) -> list[Task[T]]:
        """Return pending tasks matching predicate in dequeue order."""
        return [task for task in self._ordered_tasks() if predicate(task)]

    def is_empty(self) -> bool:
        """Return True when the queue has no pending tasks."""
        return not self._tasks

    def clear(self) -> None:
        """Remove all pending tasks from the queue."""
        self._tasks.clear()
        self._heap.clear()
        self._queue_order.clear()
        self._sequence = count()

    def __len__(self) -> int:
        """Return the number of pending tasks."""
        return self.size

    def __bool__(self) -> bool:
        """Return True when the queue contains at least one pending task."""
        return not self.is_empty()

    def __iter__(self) -> Iterator[Task[T]]:
        """Iterate over pending tasks in priority order without removing them."""
        return iter(self._ordered_tasks())

    def __contains__(self, task_id: object) -> bool:
        """Return True if task_id identifies a pending task."""
        if isinstance(task_id, UUID):
            return task_id in self._tasks

        if isinstance(task_id, str):
            try:
                return UUID(task_id) in self._tasks
            except ValueError:
                return False

        return False

    def __enter__(self) -> PriorityTaskQueue[T]:
        """Enter a managed queue scope."""
        return self

    def __exit__(
        self,
        exc_type: type[BaseException] | None,
        exc_value: BaseException | None,
        traceback: TracebackType | None,
    ) -> bool:
        """Clear pending tasks on context exit and propagate exceptions."""
        self.clear()
        return False

    def __repr__(self) -> str:
        """Return a concise debugging representation."""
        counts: dict[int, int] = {}

        for task in self._tasks.values():
            counts[task.priority] = counts.get(task.priority, 0) + 1

        priorities = {
            priority: counts[priority]
            for priority in sorted(counts, reverse=True)
        }

        return f"{type(self).__name__}(size={self.size}, priorities={priorities})"

    def _require_task(self, task_id: TaskIdLike) -> tuple[UUID, Task[T]]:
        """Return a normalized task ID and task, or raise TaskNotFoundError."""
        task_uuid = self._coerce_task_id(task_id)
        task = self._tasks.get(task_uuid)

        if task is None:
            raise TaskNotFoundError(f"No pending task found for id {task_id!r}.")

        return task_uuid, task

    def _push_pending_task(self, task: Task[T]) -> None:
        """Store a pending task and push its current heap entry."""
        order = next(self._sequence)

        self._tasks[task.id] = task
        self._queue_order[task.id] = order

        heapq.heappush(self._heap, (-task.priority, order, task.id))
        self._compact_heap_if_needed()

    def _ordered_tasks(self) -> list[Task[T]]:
        """Return a snapshot of pending tasks in dequeue order."""
        return sorted(
            self._tasks.values(),
            key=lambda task: (-task.priority, self._queue_order[task.id]),
        )

    def _discard_stale_heap_entries(self) -> None:
        """Remove heap entries for canceled or reprioritized tasks."""
        while self._heap:
            _, order, task_id = self._heap[0]

            if task_id in self._tasks and self._queue_order.get(task_id) == order:
                return

            heapq.heappop(self._heap)

    def _compact_heap_if_needed(self) -> None:
        """Rebuild the heap when lazy invalidation leaves many stale entries."""
        if len(self._heap) <= max(64, len(self._tasks) * 2):
            return

        self._heap = [
            (-task.priority, self._queue_order[task_id], task_id)
            for task_id, task in self._tasks.items()
        ]
        heapq.heapify(self._heap)

    @staticmethod
    def _coerce_task_id(task_id: TaskIdLike) -> UUID:
        """Normalize UUID or UUID-string task IDs."""
        if isinstance(task_id, UUID):
            return task_id

        if isinstance(task_id, str):
            try:
                return UUID(task_id)
            except ValueError as exc:
                raise TaskNotFoundError(
                    f"No pending task found for id {task_id!r}."
                ) from exc

        raise TypeError("task_id must be a UUID or UUID string")
